// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";
import "./CarNFT.sol";

contract OwnershipTransfer is Ownable {
    CarNFT public carNFT;

    struct Transfer {
        address from;
        address to;
        uint256 timestamp;
        string transferReason;
        bool isActive;
    }

    // Mapping from car ID to its transfer history
    mapping(uint256 => Transfer[]) public transferHistory;

    // Mapping to track pending transfers
    mapping(uint256 => Transfer) public pendingTransfers;

    event TransferInitiated(uint256 indexed carId, address indexed from, address indexed to, uint256 timestamp);
    event TransferCompleted(uint256 indexed carId, address indexed from, address indexed to, uint256 timestamp);
    event TransferCancelled(uint256 indexed carId, address indexed from, address indexed to, uint256 timestamp);

    constructor(address _carNFTAddress) {
        carNFT = CarNFT(_carNFTAddress);
    }

    modifier onlyCarOwner(uint256 carId) {
        require(carNFT.ownerOf(carId) == msg.sender, "Not the car owner");
        _;
    }

    function initiateTransfer(
        uint256 carId,
        address to,
        string memory transferReason
    ) public onlyCarOwner(carId) {
        require(to != address(0), "Invalid recipient address");
        require(pendingTransfers[carId].isActive == false, "Transfer already pending");

        Transfer memory newTransfer = Transfer({
            from: msg.sender,
            to: to,
            timestamp: block.timestamp,
            transferReason: transferReason,
            isActive: true
        });

        pendingTransfers[carId] = newTransfer;
        emit TransferInitiated(carId, msg.sender, to, block.timestamp);
    }

    function acceptTransfer(uint256 carId) public {
        Transfer memory pending = pendingTransfers[carId];
        require(pending.isActive, "No active transfer");
        require(pending.to == msg.sender, "Not the intended recipient");

        // Transfer the NFT
        address from = pending.from;
        carNFT.transferFrom(from, msg.sender, carId);

        // Record the transfer in history
        transferHistory[carId].push(pending);

        // Clear the pending transfer
        delete pendingTransfers[carId];

        emit TransferCompleted(carId, from, msg.sender, block.timestamp);
    }

    function cancelTransfer(uint256 carId) public {
        Transfer memory pending = pendingTransfers[carId];
        require(pending.isActive, "No active transfer");
        require(pending.from == msg.sender || pending.to == msg.sender, "Not authorized");

        delete pendingTransfers[carId];
        emit TransferCancelled(carId, pending.from, pending.to, block.timestamp);
    }

    function getTransferHistory(uint256 carId) public view returns (Transfer[] memory) {
        return transferHistory[carId];
    }

    function getPendingTransfer(uint256 carId) public view returns (
        address from,
        address to,
        uint256 timestamp,
        string memory transferReason,
        bool isActive
    ) {
        Transfer memory transfer = pendingTransfers[carId];
        return (
            transfer.from,
            transfer.to,
            transfer.timestamp,
            transfer.transferReason,
            transfer.isActive
        );
    }
}

contracts/ServiceHistory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";
import "./CarNFT.sol";

contract ServiceHistory is Ownable {
    struct ServiceRecord {
        uint256 timestamp;
        string serviceType;
        string description;
        string serviceProvider;
        uint256 mileage;
        string[] partsReplaced;
    }

    CarNFT public carNFT;
    mapping(uint256 => ServiceRecord[]) private _serviceHistory;
    mapping(uint256 => bool) private _isAccident;
    mapping(uint256 => string[]) private _modifications;

    event ServiceRecorded(uint256 indexed carId, string serviceType, uint256 timestamp);
    event AccidentReported(uint256 indexed carId, string description, uint256 timestamp);
    event ModificationAdded(uint256 indexed carId, string modification, uint256 timestamp);

    constructor(address _carNFTAddress) {
        carNFT = CarNFT(_carNFTAddress);
    }

    function recordService(
        uint256 carId,
        string memory serviceType,
        string memory description,
        string memory serviceProvider,
        uint256 mileage,
        string[] memory partsReplaced
    ) public {
        require(carNFT.ownerOf(carId) == msg.sender, "Only car owner can record service");

        ServiceRecord memory newRecord = ServiceRecord({
            timestamp: block.timestamp,
            serviceType: serviceType,
            description: description,
            serviceProvider: serviceProvider,
            mileage: mileage,
            partsReplaced: partsReplaced
        });

        _serviceHistory[carId].push(newRecord);
        emit ServiceRecorded(carId, serviceType, block.timestamp);
    }

    function reportAccident(uint256 carId, string memory description) public {
        require(carNFT.ownerOf(carId) == msg.sender, "Only car owner can report accident");
        _isAccident[carId] = true;
        emit AccidentReported(carId, description, block.timestamp);
    }

    function addModification(uint256 carId, string memory modification) public {
        require(carNFT.ownerOf(carId) == msg.sender, "Only car owner can add modification");
        _modifications[carId].push(modification);
        emit ModificationAdded(carId, modification, block.timestamp);
    }

    function getServiceHistory(uint256 carId) public view returns (ServiceRecord[] memory) {
        return _serviceHistory[carId];
    }

    function hasAccidentHistory(uint256 carId) public view returns (bool) {
        return _isAccident[carId];
    }

    function getModifications(uint256 carId) public view returns (string[] memory) {
        return _modifications[carId];
    }
}

contracts/TransactionManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "./CarNFT.sol";
import "./OwnershipTransfer.sol";

contract TransactionManager is Ownable, ReentrancyGuard {
    CarNFT public carNFT;
    OwnershipTransfer public ownershipTransfer;

    struct Transaction {
        uint256 carId;
        address seller;
        address buyer;
        uint256 price;
        uint256 timestamp;
        TransactionStatus status;
        string transactionType; // e.g., "Sale", "Lease", "Trade-in"
        bytes32 documentHash; // Hash of any supporting documents
    }

    enum TransactionStatus { 
        Pending,
        Completed,
        Cancelled,
        Disputed
    }

    // Mapping from transaction ID to Transaction
    mapping(uint256 => Transaction) public transactions;
    uint256 private transactionCounter;

    // Mapping from car ID to its transaction history
    mapping(uint256 => uint256[]) public carTransactions;

    // Escrow balances
    mapping(uint256 => uint256) public escrowBalances;

    event TransactionCreated(uint256 indexed transactionId, uint256 indexed carId, address seller, address buyer, uint256 price);
    event TransactionCompleted(uint256 indexed transactionId, uint256 indexed carId);
    event TransactionCancelled(uint256 indexed transactionId, uint256 indexed carId);
    event DisputeRaised(uint256 indexed transactionId, address complainant);
    event EscrowDeposited(uint256 indexed transactionId, uint256 amount);
    event EscrowReleased(uint256 indexed transactionId, address recipient, uint256 amount);

    constructor(address _carNFTAddress, address _ownershipTransferAddress) {
        carNFT = CarNFT(_carNFTAddress);
        ownershipTransfer = OwnershipTransfer(_ownershipTransferAddress);
    }

    function createTransaction(
        uint256 carId,
        address buyer,
        uint256 price,
        string memory transactionType,
        bytes32 documentHash
    ) public returns (uint256) {
        require(carNFT.ownerOf(carId) == msg.sender, "Not the car owner");

        uint256 transactionId = transactionCounter++;

        Transaction memory newTransaction = Transaction({
            carId: carId,
            seller: msg.sender,
            buyer: buyer,
            price: price,
            timestamp: block.timestamp,
            status: TransactionStatus.Pending,
            transactionType: transactionType,
            documentHash: documentHash
        });

        transactions[transactionId] = newTransaction;
        carTransactions[carId].push(transactionId);

        emit TransactionCreated(transactionId, carId, msg.sender, buyer, price);
        return transactionId;
    }

    function depositEscrow(uint256 transactionId) public payable nonReentrant {
        Transaction storage transaction = transactions[transactionId];
        require(transaction.buyer == msg.sender, "Not the buyer");
        require(transaction.status == TransactionStatus.Pending, "Invalid transaction status");
        require(msg.value == transaction.price, "Incorrect payment amount");

        escrowBalances[transactionId] = msg.value;
        emit EscrowDeposited(transactionId, msg.value);
    }

    function completeTransaction(uint256 transactionId) public nonReentrant {
        Transaction storage transaction = transactions[transactionId];
        require(transaction.status == TransactionStatus.Pending, "Invalid transaction status");
        require(escrowBalances[transactionId] == transaction.price, "Escrow not funded");
        require(msg.sender == transaction.buyer || msg.sender == transaction.seller, "Not authorized");

        // Transfer ownership
        ownershipTransfer.initiateTransfer(
            transaction.carId,
            transaction.buyer,
            transaction.transactionType
        );

        // Release escrow to seller
        uint256 amount = escrowBalances[transactionId];
        escrowBalances[transactionId] = 0;
        payable(transaction.seller).transfer(amount);

        transaction.status = TransactionStatus.Completed;

        emit TransactionCompleted(transactionId, transaction.carId);
        emit EscrowReleased(transactionId, transaction.seller, amount);
    }

    function cancelTransaction(uint256 transactionId) public {
        Transaction storage transaction = transactions[transactionId];
        require(transaction.status == TransactionStatus.Pending, "Invalid transaction status");
        require(msg.sender == transaction.buyer || msg.sender == transaction.seller, "Not authorized");

        // Refund escrow to buyer if any
        uint256 escrowAmount = escrowBalances[transactionId];
        if (escrowAmount > 0) {
            escrowBalances[transactionId] = 0;
            payable(transaction.buyer).transfer(escrowAmount);
            emit EscrowReleased(transactionId, transaction.buyer, escrowAmount);
        }

        transaction.status = TransactionStatus.Cancelled;
        emit TransactionCancelled(transactionId, transaction.carId);
    }

    function raiseDispute(uint256 transactionId) public {
        Transaction storage transaction = transactions[transactionId];
        require(msg.sender == transaction.buyer || msg.sender == transaction.seller, "Not authorized");
        require(transaction.status == TransactionStatus.Pending, "Invalid transaction status");

        transaction.status = TransactionStatus.Disputed;
        emit DisputeRaised(transactionId, msg.sender);
    }

    function getTransaction(uint256 transactionId) public view returns (
        uint256 carId,
        address seller,
        address buyer,
        uint256 price,
        uint256 timestamp,
        TransactionStatus status,
        string memory transactionType,
        bytes32 documentHash
    ) {
        Transaction memory transaction = transactions[transactionId];
        return (
            transaction.carId,
            transaction.seller,
            transaction.buyer,
            transaction.price,
            transaction.timestamp,
            transaction.status,
            transaction.transactionType,
            transaction.documentHash
        );
    }

    function getCarTransactionHistory(uint256 carId) public view returns (uint256[] memory) {
        return carTransactions[carId];
    }
}

